			"width": 1440,
			"height": 960,
			"display": "auto"
		},
		"structure": [
			{
				"item": "viz_tkz0p3Qf",
				"type": "block",
				"position": {
					"x": 0,
					"y": 0,
					"w": 1430,
					"h": 660
				}
			}
		],
		"globalInputs": []
	},
	"description": "",
	"title": "Cribl Decrypt Overview"
}
